export const app = window.firebase.initializeApp(firebaseConfig);
const database = window.firebase.database();

export async function readPostDataFromServer(id) {
  try {
    const snapshot = await database.ref().child("Books").child(id).get();

    if (snapshot.exists()) {
      return snapshot.val();
    } else {
      return undefined;
    }
  } catch (error) {
    return error;
  }
}

const store = window.firebase.firestore();
const dashboardRef = store.collection("Dashboard");

export async function readBookTitlesAsync() {
  const bookRef = dashboardRef.doc("books");
  const res = await bookRef.get();

  return res.data().data;
}

export async function readImagesAsync() {
  const imageRef = dashboardRef.doc("images");
  const res = await imageRef.get();

  return res.data().data;
}
